PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE dishes (
	id INTEGER NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	category VARCHAR(100) NOT NULL, 
	ingredients_quantified JSON NOT NULL, 
	applicable_meals JSON NOT NULL, 
	flavor VARCHAR(100) NOT NULL, 
	cost_per_serving FLOAT NOT NULL, 
	nutrition JSON NOT NULL, 
	tags JSON NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE standard_quotas (
	id INTEGER NOT NULL, 
	class_type VARCHAR(50) NOT NULL, 
	quotas JSON NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE users (
	id INTEGER NOT NULL, 
	username VARCHAR(50) NOT NULL, 
	hashed_password VARCHAR(255) NOT NULL, 
	is_active BOOLEAN, 
	role VARCHAR(20), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE menu_histories (
	id VARCHAR(50) NOT NULL, 
	user_id INTEGER NOT NULL, 
	name VARCHAR(100), 
	menu_data JSON, 
	metrics_data JSON, 
	config_data JSON, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE chat_sessions (
	id VARCHAR(50) NOT NULL, 
	user_id INTEGER NOT NULL, 
	title VARCHAR(200) NOT NULL, 
	messages JSON NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE INDEX ix_dishes_category ON dishes (category);
CREATE INDEX ix_dishes_name ON dishes (name);
CREATE INDEX ix_dishes_id ON dishes (id);
CREATE INDEX ix_standard_quotas_id ON standard_quotas (id);
CREATE UNIQUE INDEX ix_standard_quotas_class_type ON standard_quotas (class_type);
CREATE UNIQUE INDEX ix_users_username ON users (username);
CREATE INDEX ix_users_id ON users (id);
CREATE INDEX ix_menu_histories_user_id ON menu_histories (user_id);
CREATE INDEX ix_menu_histories_id ON menu_histories (id);
CREATE INDEX ix_chat_sessions_id ON chat_sessions (id);
CREATE INDEX ix_chat_sessions_user_id ON chat_sessions (user_id);
COMMIT;
